mapper.select:
SELECT
    id, seller_id, category_id, title, description, price,
    stock_quantity, `condition`, location, image_urls, `status`,
    created_at, updated_at,latitude,longitude
FROM products


        AND title LIKE CONCAT('%', #{keyword}, '%')


        AND category_id = #{categoryId}


        AND sub_category_id = #{subCategoryId}


        AND brand = #{brand}


        AND price >= #{priceMin}


        AND price <= #{priceMax}


        AND image_urls IS NOT NULL AND image_urls <> ''


        AND free_shipping = 1


        AND invoice = 1


        AND rating >= #{minRating}




        ORDER BY created_at DESC



            ORDER BY price ASC
            ORDER BY price DESC



        ORDER BY created_at DESC, id DESC

SELECT
    id, seller_id, category_id, title, description, price,
    stock_quantity, `condition`, location, image_urls, `status`,
    created_at, updated_at,
    latitude, longitude,
    6371 * ACOS(
        COS(RADIANS(#{lat})) * COS(RADIANS(latitude)) *
        COS(RADIANS(longitude) - RADIANS(#{lng})) +
        SIN(RADIANS(#{lat})) * SIN(RADIANS(latitude))
    ) AS distanceKm
FROM products
WHERE latitude IS NOT NULL AND longitude IS NOT NULL
AND category_id = #{categoryId}
AND price >= #{minPrice}
AND price <= #{maxPrice}
AND title LIKE CONCAT('%', #{keyword}, '%')

HAVING distanceKm <= #{radiusKm}

ORDER BY distanceKm ASC, updated_at DESC
LIMIT #{limit}
OFFSET #{offset}

