UPDATE products
SET `status` = #{status}, updated_at = NOW()
WHERE id = #{id}

UPDATE products
SET price = #{price}, updated_at = NOW()
WHERE id = #{id}

UPDATE products
SET location = #{location}, updated_at = NOW()
WHERE id = #{id}

UPDATE products
SET latitude = #{latitude}, longitude = #{longitude}, updated_at = NOW()
WHERE id = #{id}
